import{_ as e}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as t,o as i,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Auto Tagging","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/Other/auto-tagging.md","filePath":"bn-BD/Other/auto-tagging.md","lastUpdated":1781962217000}'),n={name:"bn-BD/Other/auto-tagging.md"};function o(d,a,g,c,p,r){return i(),s("div",null,[...a[0]||(a[0]=[l('<h1 id="auto-tagging" tabindex="-1">Auto Tagging <a class="header-anchor" href="#auto-tagging" aria-label="Permalink to &quot;Auto Tagging&quot;">​</a></h1><p>Auto tagging এখানে configure করা হয়:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>এটি automatically image tags generate করে। Search, random image filtering, public gallery filtering এবং age-rating access control-এ এই tags কাজে লাগে।</p><h2 id="auto-tagging-কী-করতে-পারে" tabindex="-1">Auto Tagging কী করতে পারে <a class="header-anchor" href="#auto-tagging-কী-করতে-পারে" aria-label="Permalink to &quot;Auto Tagging কী করতে পারে&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Content tags generate</td><td>People, scenes, objects, art style এবং similar visual content-এর tags যোগ করে।</td></tr><tr><td>Character tags generate</td><td>Anime images এবং illustrations-এর জন্য useful।</td></tr><tr><td>Orientation tags যোগ</td><td><code>landscape</code>, <code>portrait</code> বা <code>square</code> যোগ করে।</td></tr><tr><td>Image rating যোগ</td><td>General, sensitive, questionable বা explicit content-এর জন্য <code>G/S/Q/E</code> rating results save করে।</td></tr><tr><td>Auto-tag on upload</td><td>Newly uploaded images automatically tagging flow-তে যায়।</td></tr><tr><td>Batch tagging</td><td>সব folders বা selected folders-এর পুরোনো images-এ tags যোগ করে।</td></tr></tbody></table><h2 id="আগে-যা-লাগবে" tabindex="-1">আগে যা লাগবে <a class="header-anchor" href="#আগে-যা-লাগবে" aria-label="Permalink to &quot;আগে যা লাগবে&quot;">​</a></h2><p>কমপক্ষে একটি accessible Hugging Face Space URL প্রস্তুত রাখুন।</p><p>Recommended পদ্ধতি হলো SmilingWolf-এর <code>wd-tagger</code> Space নিজের Hugging Face account-এ duplicate করা:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>Temporary testing-এর জন্য public Space ব্যবহার করা যায়, কিন্তু public Spaces অনেক users share করে। Queue হতে পারে, slow হতে পারে বা unavailable হতে পারে। নিজের account-এর duplicated Space long-term auto tagging-এর জন্য বেশি stable।</p><h2 id="smilingwolf-এর-space-duplicate-করা" tabindex="-1">SmilingWolf-এর Space Duplicate করা <a class="header-anchor" href="#smilingwolf-এর-space-duplicate-করা" aria-label="Permalink to &quot;SmilingWolf-এর Space Duplicate করা&quot;">​</a></h2><ol><li>Hugging Face-এ sign in করুন।</li><li><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code> খুলুন।</li></ol><p><img src="'+e+`" alt="SmilingWolf public Space" loading="lazy"></p><ol start="3"><li>Upper-right corner-এর three-dot menu ক্লিক করুন।</li><li><code>Duplicate this Space</code> নির্বাচন করুন।</li><li>Default Space name রাখুন বা নিজের নাম দিন, যেমন <code>wd-tagger</code>।</li><li>Visibility <code>Public</code> রাখুন। Public Spaces ImgBed থেকে call করা সহজ।</li><li>শুরুতে default free hardware রাখুন। Queueing স্পষ্ট হলে পরে upgrade করুন।</li><li>Space create করে build শেষ হওয়া পর্যন্ত অপেক্ষা করুন।</li></ol><p>Build শেষ হলে আপনার Space page খুলুন। URL সাধারণত এমন হয়:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>Browser URL copy করে ImgBed-এর <code>Space URLs</code>-এ paste করুন।</p><h2 id="multiple-space-urls-দেওয়া" tabindex="-1">Multiple Space URLs দেওয়া <a class="header-anchor" href="#multiple-space-urls-দেওয়া" aria-label="Permalink to &quot;Multiple Space URLs দেওয়া&quot;">​</a></h2><p>প্রতি line-এ একটি Space URL দিন।</p><p>Examples:</p><table tabindex="0"><thead><tr><th>Value</th><th>Description</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>SmilingWolf public Space। Temporary testing-এর জন্য ভালো।</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>Copied Space page URL।</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>আপনার duplicated Space page URL।</td></tr></tbody></table><p>Multiple URLs দেওয়া যায়। ImgBed একসঙ্গে multiple Spaces ব্যবহার করে, ফলে speed ভালো হতে পারে।</p><p>একটি Space temporarily unavailable থাকলেও অন্যগুলো processing চালিয়ে যেতে পারে।</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>প্রস্তুত করা Space URLs দিন। অন্তত একটি দরকার।</td></tr><tr><td>Target folder</td><td>সব folders-এর জন্য empty রাখুন। Specific directory process করতে চাইলে folder select করুন।</td></tr><tr><td>Recognition model</td><td>Default হিসেবে <code>wd-swinv2-tagger-v3</code> রাখুন।</td></tr><tr><td>General tag threshold</td><td>Default বেশিরভাগ images-এর জন্য ঠিক। Lower values বেশি tags দেয়; higher values কম tags দেয়।</td></tr><tr><td>Character tag threshold</td><td>Default conservative, ভুল character tags এড়াতে সাহায্য করে।</td></tr><tr><td><code>MCut</code> automatic threshold</td><td>শুরুতে off রাখুন। Model দিয়ে tag count automatically ঠিক করাতে চাইলে on করুন।</td></tr><tr><td>Auto-tag on upload</td><td>Newly uploaded images automatically tags পাক চাইলে on করুন।</td></tr><tr><td>Start tagging</td><td>পুরোনো images manually batch-tag করে।</td></tr></tbody></table><h2 id="recommended-starting-values" tabindex="-1">Recommended Starting Values <a class="header-anchor" href="#recommended-starting-values" aria-label="Permalink to &quot;Recommended Starting Values&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommended Value</th></tr></thead><tbody><tr><td>Recognition model</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>General tag threshold</td><td><code>0.35</code></td></tr><tr><td>Character tag threshold</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>শুরুতে Off</td></tr><tr><td>Auto-tag on upload</td><td>দরকার হলে Enable</td></tr></tbody></table><p>Tags বেশি হলে general threshold একটু বাড়ান।</p><p>Tags কম হলে general threshold একটু কমান।</p><h2 id="batch-tagging" tabindex="-1">Batch Tagging <a class="header-anchor" href="#batch-tagging" aria-label="Permalink to &quot;Batch Tagging&quot;">​</a></h2><ol><li><code>Space URLs</code> পূরণ করুন।</li><li>Target folder নির্বাচন করুন।</li><li>Start tagging ক্লিক করুন।</li><li>Progress শেষ হওয়া পর্যন্ত অপেক্ষা করুন।</li></ol><p>Target folder empty থাকলে ImgBed সব folders process করে।</p><p>Batch tagging পুরোনো images-এর জন্য ভালো। New images-এর জন্য auto-tag on upload enable করুন, তাহলে বারবার manually run করতে হবে না।</p><h2 id="auto-tag-on-upload" tabindex="-1">Auto-Tag on Upload <a class="header-anchor" href="#auto-tag-on-upload" aria-label="Permalink to &quot;Auto-Tag on Upload&quot;">​</a></h2><p>Auto-tag on upload enabled হলে newly uploaded images automatically configured <code>Space URLs</code> call করে।</p><p>Long-term use-এর জন্য এটি suitable।</p><p>আপনার Space queueing করলেও upload আগে finish হতে পারে, tagging পরে continue করবে।</p><h2 id="কোন-images-process-হয়" tabindex="-1">কোন Images Process হয় <a class="header-anchor" href="#কোন-images-process-হয়" aria-label="Permalink to &quot;কোন Images Process হয়&quot;">​</a></h2><p>Auto tagging মূলত image files process করে।</p><p>যে images-এ complete tags, orientation, rating, width এবং height আগে থেকেই আছে, unnecessary Space calls এড়াতে সেগুলো skip করা হয়।</p><p>যেখানে সম্ভব ImgBed শুধু missing information পূরণ করে। যেমন, শুধু orientation missing হলে full content tag flow না চালিয়ে orientation যোগ করার চেষ্টা করে।</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="নিজের-space-duplicate-করব-কেন" tabindex="-1">নিজের Space Duplicate করব কেন? <a class="header-anchor" href="#নিজের-space-duplicate-করব-কেন" aria-label="Permalink to &quot;নিজের Space Duplicate করব কেন?&quot;">​</a></h3><p>Public Spaces অনেক users share করে। আপনার duplicated Space মূলত আপনার ImgBed site ব্যবহার করে, তাই সাধারণত faster এবং reliable।</p><h3 id="space-বারবার-starting-up-দেখাচ্ছে" tabindex="-1">Space বারবার Starting Up দেখাচ্ছে <a class="header-anchor" href="#space-বারবার-starting-up-দেখাচ্ছে" aria-label="Permalink to &quot;Space বারবার Starting Up দেখাচ্ছে&quot;">​</a></h3><p>প্রথম creation-এর পর, বা দীর্ঘ idle period-এর পর, Space start হতে সময় নিতে পারে।</p><p>আগে আপনার Space page খুলুন। যখন normal image recognize করতে পারে, তখন ImgBed-এ ফিরে tagging start করুন।</p><h3 id="space-url-কীভাবে-copy-করব" tabindex="-1">Space URL কীভাবে Copy করব? <a class="header-anchor" href="#space-url-কীভাবে-copy-করব" aria-label="Permalink to &quot;Space URL কীভাবে Copy করব?&quot;">​</a></h3><p>আপনার Hugging Face Space page খুলে browser address copy করুন।</p><p>Examples:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="multiple-spaces-যোগ-করা-যায়" tabindex="-1">Multiple Spaces যোগ করা যায়? <a class="header-anchor" href="#multiple-spaces-যোগ-করা-যায়" aria-label="Permalink to &quot;Multiple Spaces যোগ করা যায়?&quot;">​</a></h3><p>হ্যাঁ। প্রতি line-এ একটি Space URL দিন।</p><p>Multiple Spaces একসঙ্গে images process করে এবং অনেক images থাকলে useful।</p><h3 id="tags-english-এ-কেন" tabindex="-1">Tags English-এ কেন? <a class="header-anchor" href="#tags-english-এ-কেন" aria-label="Permalink to &quot;Tags English-এ কেন?&quot;">​</a></h3><p>SmilingWolf models English tags output করে। এটি expected।</p><p>Tags মূলত search, filtering, random image API এবং public gallery filters-এর জন্য ব্যবহৃত হয়।</p><h3 id="rating-tags-কী-কাজে-লাগে" tabindex="-1">Rating Tags কী কাজে লাগে? <a class="header-anchor" href="#rating-tags-কী-কাজে-লাগে" aria-label="Permalink to &quot;Rating Tags কী কাজে লাগে?&quot;">​</a></h3><p>Rating results Security Settings-এর access mode-এর সঙ্গে কাজ করে।</p><p>যেমন, visitor access age rating দিয়ে limited হলে public browsing এবং random image features সেই rules অনুযায়ী images filter করে।</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hugging Face-এ sign in করুন</span></span>
<span class="line"><span>-&gt; SmilingWolf/wd-tagger খুলুন</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; Space build শেষ হওয়া পর্যন্ত অপেক্ষা করুন</span></span>
<span class="line"><span>-&gt; আপনার Space URL copy করুন</span></span>
<span class="line"><span>-&gt; ImgBed-এ Space URLs পূরণ করুন</span></span>
<span class="line"><span>-&gt; Model এবং thresholds নির্বাচন করুন</span></span>
<span class="line"><span>-&gt; Start tagging করুন বা auto-tag on upload enable করুন</span></span></code></pre></div>`,63)])])}const b=t(n,[["render",o]]);export{m as __pageData,b as default};
